function PlantWatering() {
  const [plants, setPlants] = React.useState([
    { name: 'Monstera', interval: 7, lastWatered: new Date(Date.now() - 3 * 86400000).toISOString().slice(0, 10) },
    { name: 'Snake Plant', interval: 14, lastWatered: new Date(Date.now() - 10 * 86400000).toISOString().slice(0, 10) },
    { name: 'Pothos', interval: 5, lastWatered: new Date(Date.now() - 1 * 86400000).toISOString().slice(0, 10) }
  ]);
  const [newName, setNewName] = React.useState('');
  const [newInterval, setNewInterval] = React.useState('7');

  function daysSince(dateStr) {
    const d = new Date(dateStr);
    const diff = Math.floor((Date.now() - d.getTime()) / 86400000);
    return diff;
  }

  function waterPlant(idx) {
    const today = new Date().toISOString().slice(0, 10);
    setPlants(plants.map((p, i) => i === idx ? { ...p, lastWatered: today } : p));
  }

  function addPlant() {
    if (!newName.trim()) return;
    const today = new Date().toISOString().slice(0, 10);
    setPlants([...plants, { name: newName, interval: parseInt(newInterval) || 7, lastWatered: today }]);
    setNewName('');
    setNewInterval('7');
  }

  function removePlant(idx) {
    setPlants(plants.filter((_, i) => i !== idx));
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>Plant Watering</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input placeholder="Plant name" value={newName} onChange={e => setNewName(e.target.value)} style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <input placeholder="Days" type="number" value={newInterval} onChange={e => setNewInterval(e.target.value)} style={{ width: 60, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <button onClick={addPlant} style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: '#16a34a', color: '#fff', fontSize: 13, cursor: 'pointer' }}>Add</button>
      </div>
      <div style={{ flex: 1, overflowY: 'auto' }}>
        {plants.map((plant, i) => {
          const days = daysSince(plant.lastWatered);
          const overdue = days >= plant.interval;
          const pct = Math.min(100, Math.round((days / plant.interval) * 100));
          return (
            <div key={i} style={{ marginBottom: 12, padding: 12, borderRadius: 8, background: overdue ? '#fef2f2' : '#f0fdf4', border: '1px solid ' + (overdue ? '#fecaca' : '#bbf7d0') }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div style={{ fontWeight: 600, fontSize: 14, color: '#1a1a1a' }}>{plant.name}</div>
                <button onClick={() => removePlant(i)} style={{ background: 'transparent', border: 'none', color: '#999', cursor: 'pointer', fontSize: 16 }}>x</button>
              </div>
              <div style={{ fontSize: 12, color: overdue ? '#dc2626' : '#166534', marginTop: 4 }}>
                {overdue ? 'Overdue by ' + (days - plant.interval) + ' days' : 'Next water in ' + (plant.interval - days) + ' days'}
              </div>
              <div style={{ marginTop: 8, display: 'flex', alignItems: 'center', gap: 10 }}>
                <div style={{ flex: 1, height: 8, background: '#e5e7eb', borderRadius: 4, overflow: 'hidden' }}>
                  <div style={{ width: pct + '%', height: '100%', background: overdue ? '#dc2626' : '#16a34a', borderRadius: 4 }} />
                </div>
                <button onClick={() => waterPlant(i)} style={{ padding: '4px 12px', borderRadius: 6, border: 'none', background: '#16a34a', color: '#fff', fontSize: 12, cursor: 'pointer' }}>Water</button>
              </div>
            </div>
          );
        })}
        {plants.length === 0 && <div style={{ textAlign: 'center', color: '#999', fontSize: 13, padding: 20 }}>No plants added yet.</div>}
      </div>
    </div>
  );
}
render(<PlantWatering/>);
